from collections import Counter
class Solution:
    def longestSpecialPath(self, edges, nums):
        n = len(nums)
        adj = [[] for _ in range(n)]
        for u, v, w in edges:
            adj[u].append((v, w))
            adj[v].append((u, w))
        parent = [-1] * n
        children = [[] for _ in range(n)]
        visited = [False] * n
        visited[0] = True
        stack = [0]
        while stack:
            u = stack.pop()
            for v, w in adj[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[v] = u
                    children[u].append((v, w))
                    stack.append(v)
        best_len = 0
        best_nodes = 1
        def dfs(node, path, dist):
            nonlocal best_len, best_nodes
            vals = [nums[x] for x in path]
            c = Counter(vals)
            twos = sum(1 for v in c.values() if v == 2)
            ge3 = sum(1 for v in c.values() if v >= 3)
            if ge3 == 0 and twos <= 1:
                if dist > best_len or (dist == best_len and len(path) < best_nodes):
                    best_len = dist
                    best_nodes = len(path)
            else:
                return
            for child, w in children[node]:
                dfs(child, path + [child], dist + w)
        for start in range(n):
            dfs(start, [start], 0)
        return [best_len, best_nodes]

