var longestSpecialPath = function(edges, nums) {
    const n = nums.length;
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        adj[v].push([u, w]);
    }
    const freq = new Map();
    let cntEq2 = 0, cntGe3 = 0, left = 0;
    let bestLen = 0, bestNodes = 1;
    const pathNodes = new Array(n + 1).fill(0);
    const dist = new Array(n + 1).fill(0);
    function addValue(v) {
        const old = freq.get(v) || 0;
        freq.set(v, old + 1);
        if (old === 1) cntEq2++;
        else if (old === 2) { cntEq2--; cntGe3++; }
    }
    function removeValue(v) {
        const old = freq.get(v);
        freq.set(v, old - 1);
        if (old === 2) cntEq2--;
        else if (old === 3) { cntGe3--; cntEq2++; }
    }
    pathNodes[0] = 0;
    addValue(nums[0]);
    const leftBefore0 = left;
    const evicted0 = [];
    while (cntGe3 > 0 || cntEq2 > 1) {
        const v = nums[pathNodes[left]];
        removeValue(v);
        evicted0.push(v);
        left++;
    }
    {
        const curLen = dist[0] - dist[left];
        const curNodes = 0 - left + 1;
        if (curLen > bestLen || (curLen === bestLen && curNodes < bestNodes)) {
            bestLen = curLen; bestNodes = curNodes;
        }
    }
    const stack = [{ node: 0, parent: -1, di: 0, iterIdx: 0, leftBefore: leftBefore0, evicted: evicted0 }];
    while (stack.length) {
        const frame = stack[stack.length - 1];
        const { node, parent, di } = frame;
        const neighbors = adj[node];
        let advanced = false;
        while (frame.iterIdx < neighbors.length) {
            const [nxt, w] = neighbors[frame.iterIdx];
            frame.iterIdx++;
            if (nxt === parent) continue;
            const ndi = di + 1;
            pathNodes[ndi] = nxt;
            dist[ndi] = dist[di] + w;
            addValue(nums[nxt]);
            const lb = left;
            const ev = [];
            while (cntGe3 > 0 || cntEq2 > 1) {
                const v = nums[pathNodes[left]];
                removeValue(v);
                ev.push(v);
                left++;
            }
            const cl = dist[ndi] - dist[left];
            const cn = ndi - left + 1;
            if (cl > bestLen || (cl === bestLen && cn < bestNodes)) {
                bestLen = cl; bestNodes = cn;
            }
            stack.push({ node: nxt, parent: node, di: ndi, iterIdx: 0, leftBefore: lb, evicted: ev });
            advanced = true;
            break;
        }
        if (!advanced) {
            for (let i = frame.evicted.length - 1; i >= 0; i--) addValue(frame.evicted[i]);
            removeValue(nums[node]);
            left = frame.leftBefore;
            stack.pop();
        }
    }
    return [bestLen, bestNodes];
};
